from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body into a fluent, single sentence.
    Groups related predicates and creates natural flowing text with proper connectors.
    """
    if not triples:
        return ""

    # Group predicates by category
    discovery_predicates = {"discoverer", "discovered", "formerName", "absoluteMagnitude"}
    physical_predicates = {"mass", "density", "surfaceArea", "escapeVelocity", "averageSpeed", "rotationPeriod"}
    temperature_predicates = {"temperature", "maximumTemperature", "meanTemperature", "minimumTemperature"}
    orbital_predicates = {"apoapsis", "periapsis", "orbitalPeriod", "epoch"}
    person_predicates = {"birthPlace", "birthDate", "deathPlace", "deathDate", "deathCause", "nationality", "stateOfOrigin", "almaMater", "doctoralStudent"}

    # Collect triples by category
    discovery_triples = []
    physical_triples = []
    temperature_triples = []
    orbital_triples = []
    person_triples = []

    for t in triples:
        if t.predicate in discovery_predicates:
            discovery_triples.append(t)
        elif t.predicate in physical_predicates:
            physical_triples.append(t)
        elif t.predicate in temperature_predicates:
            temperature_triples.append(t)
        elif t.predicate in orbital_predicates:
            orbital_triples.append(t)
        elif t.predicate in person_predicates:
            person_triples.append(t)

    # Subject from first triple
    subject = triples[0].subject

    # Build sentence parts
    parts = []

    # Discovery info
    if discovery_triples:
        discovery_parts = []
        for t in discovery_triples:
            p, o = t.predicate, t.object
            if p == "discoverer":
                discovery_parts.append(f"discovered by {o}")
            elif p == "discovered":
                discovery_parts.append(f"discovered on {o}")
            elif p == "formerName":
                discovery_parts.append(f"formerly known as {o}")
            elif p == "absoluteMagnitude":
                discovery_parts.append(f"absolute magnitude {o}")
        if discovery_parts:
            parts.append(", ".join(discovery_parts))

    # Physical properties
    if physical_triples:
        physical_parts = []
        for t in physical_triples:
            p, o = t.predicate, t.object
            if p == "mass":
                physical_parts.append(f"mass {o}")
            elif p == "density":
                physical_parts.append(f"density {o}")
            elif p == "surfaceArea":
                physical_parts.append(f"surface area {o}")
            elif p == "escapeVelocity":
                physical_parts.append(f"escape velocity {o}")
            elif p == "averageSpeed":
                physical_parts.append(f"average speed {o}")
            elif p == "rotationPeriod":
                physical_parts.append(f"rotation period {o}")
        if physical_parts:
            parts.append("with " + ", ".join(physical_parts))

    # Temperature info
    if temperature_triples:
        temp_parts = []
        for t in temperature_triples:
            p, o = t.predicate, t.object
            if p == "temperature":
                temp_parts.append(f"temperature {o}")
            elif p == "maximumTemperature":
                temp_parts.append(f"maximum temperature {o}")
            elif p == "meanTemperature":
                temp_parts.append(f"mean temperature {o}")
            elif p == "minimumTemperature":
                temp_parts.append(f"minimum temperature {o}")
        if temp_parts:
            parts.append("with " + ", ".join(temp_parts))

    # Orbital info
    if orbital_triples:
        orbital_parts = []
        for t in orbital_triples:
            p, o = t.predicate, t.object
            if p == "apoapsis":
                orbital_parts.append(f"apoapsis {o}")
            elif p == "periapsis":
                orbital_parts.append(f"periapsis {o}")
            elif p == "orbitalPeriod":
                orbital_parts.append(f"orbital period {o}")
            elif p == "epoch":
                orbital_parts.append(f"epoch {o}")
        if orbital_parts:
            parts.append("with " + ", ".join(orbital_parts))

    # Person info
    if person_triples:
        person_parts = []
        for t in person_triples:
            p, o = t.predicate, t.object
            if p == "birthPlace":
                person_parts.append(f"born in {o}")
            elif p == "birthDate":
                person_parts.append(f"born on {o}")
            elif p == "deathPlace":
                person_parts.append(f"died in {o}")
            elif p == "deathDate":
                person_parts.append(f"died on {o}")
            elif p == "deathCause":
                person_parts.append(f"died of {o}")
            elif p == "nationality":
                person_parts.append(f"was {o}")
            elif p == "stateOfOrigin":
                person_parts.append(f"originated from {o}")
            elif p == "almaMater":
                person_parts.append(f"studied at {o}")
            elif p == "doctoralStudent":
                person_parts.append(f"supervised {o}")
        if person_parts:
            parts.append(", ".join(person_parts))

    # Build final sentence
    if parts:
        sentence = f"{subject} is a notable entity, " + ", ".join(parts) + "."
    else:
        sentence = f"{subject} has been documented."

    return sentence

# EVOLVE-BLOCK-END
